question:
What is printed?

```sql
BEGIN
  FOR i IN 1..3 LOOP
    DBMS_OUTPUT.PUT_LINE(i);
  END LOOP;
END;
```

What is printed?

```sql
BEGIN
  FOR i IN REVERSE 1..3 LOOP
    DBMS_OUTPUT.PUT_LINE(i);
  END LOOP;
END;
```

What does EXIT WHEN do?

```sql
DECLARE
  v_i NUMBER := 1;
BEGIN
  LOOP
    EXIT WHEN v_i > 3;
    v_i := v_i + 1;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE(v_i);
END;
```

What is printed?

```sql
DECLARE
  v_grade CHAR(1) := 'B';
  v_result VARCHAR2(20);
BEGIN
  v_result := CASE v_grade
    WHEN 'A' THEN 'Excellent'
    WHEN 'B' THEN 'Good'
    ELSE 'Other'
  END;
  DBMS_OUTPUT.PUT_LINE(v_result);
END;
```

What is printed?

```sql
DECLARE
  v_i NUMBER := 1;
BEGIN
  WHILE v_i <= 3 LOOP
    v_i := v_i + 1;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE(v_i);
END;
```
